  1→// LicenseCheckerLib.cs - Core library for dependency license checking
  2→// This file contains all the types and logic, shared between tests and the main app.
  3→// Architecture: ManifestParser -> LicenseLookup -> ComplianceChecker -> ReportGenerator
  4→
  5→using System.Text;
  6→using System.Text.Json;
  7→using System.Text.Json.Nodes;
  8→using System.Text.Json.Serialization;
  9→using System.Text.RegularExpressions;
 10→
 11→namespace LicenseChecker;
 12→
 13→// ── Data Models ──────────────────────────────────────────────────────────────
 14→
 15→// Represents a single dependency extracted from a manifest
 16→public record Dependency(string Name, string Version);
 17→
 18→// License compliance status for a dependency
 19→public enum LicenseStatus { Approved, Denied, Unknown }
 20→
 21→// Result of checking a single dependency against the compliance config
 22→public record ComplianceResult(string DependencyName, string Version, string? License, LicenseStatus Status);
 23→
 24→// Compliance configuration: which licenses are allowed/denied
 25→public record ComplianceConfig(
 26→    HashSet<string> AllowedLicenses,
 27→    HashSet<string> DeniedLicenses)
 28→{
 29→    // Parse config from a JSON string
 30→    public static ComplianceConfig FromJson(string json)
 31→    {
 32→        JsonNode? root;
 33→        try
 34→        {
 35→            root = JsonNode.Parse(json);
 36→        }
 37→        catch (JsonException ex)
 38→        {
 39→            throw new ConfigException($"Invalid config JSON: {ex.Message}", ex);
 40→        }
 41→
 42→        if (root is null)
 43→            throw new ConfigException("Config JSON is null");
 44→
 45→        var allowedNode = root["allowedLicenses"]
 46→            ?? throw new ConfigException("Config missing required field: allowedLicenses");
 47→        var deniedNode = root["deniedLicenses"]
 48→            ?? throw new ConfigException("Config missing required field: deniedLicenses");
 49→
 50→        var allowed = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
 51→        foreach (var item in allowedNode.AsArray())
 52→            if (item is not null) allowed.Add(item.GetValue<string>());
 53→
 54→        var denied = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
 55→        foreach (var item in deniedNode.AsArray())
 56→            if (item is not null) denied.Add(item.GetValue<string>());
 57→
 58→        return new ComplianceConfig(allowed, denied);
 59→    }
 60→}
 61→
 62→// Report data models
 63→public record ReportEntry(string DependencyName, string Version, string? License, string Status);
 64→public record ReportSummary(int Total, int Approved, int Denied, int Unknown, bool Pass);
 65→public record ComplianceReport(List<ReportEntry> Entries, ReportSummary Summary);
 66→
 67→// ── Custom Exceptions ────────────────────────────────────────────────────────
 68→
 69→public class ManifestParseException : Exception
 70→{
 71→    public ManifestParseException(string message) : base(message) { }
 72→    public ManifestParseException(string message, Exception inner) : base(message, inner) { }
 73→}
 74→
 75→public class ConfigException : Exception
 76→{
 77→    public ConfigException(string message) : base(message) { }
 78→    public ConfigException(string message, Exception inner) : base(message, inner) { }
 79→}
 80→
 81→// ── License Provider Interface & Mock ────────────────────────────────────────
 82→
 83→// Interface for license lookup so we can inject mocks for testing
 84→public interface ILicenseProvider
 85→{
 86→    string? GetLicense(string packageName, string version);
 87→}
 88→
 89→// Mock implementation that returns licenses from a pre-configured dictionary
 90→public class MockLicenseProvider : ILicenseProvider
 91→{
 92→    private readonly Dictionary<string, string> _licenses;
 93→
 94→    public MockLicenseProvider(Dictionary<string, string> licenses)
 95→    {
 96→        _licenses = licenses;
 97→    }
 98→
 99→    public string? GetLicense(string packageName, string version)
100→    {
101→        return _licenses.TryGetValue(packageName, out var license) ? license : null;
102→    }
103→}
104→
105→// ── Manifest Parser ──────────────────────────────────────────────────────────
106→
107→// Parses dependency manifests (package.json, requirements.txt)
108→public static class ManifestParser
109→{
110→    // Auto-detect manifest format from filename and parse
111→    public static List<Dependency> Parse(string filename, string content)
112→    {
113→        var name = Path.GetFileName(filename).ToLowerInvariant();
114→        return name switch
115→        {
116→            "package.json" => ParsePackageJson(content),
117→            "requirements.txt" => ParseRequirementsTxt(content),
118→            _ => throw new ManifestParseException($"Unsupported manifest format: '{filename}'")
119→        };
120→    }
121→
122→    // Parse a package.json string and extract all dependencies (dependencies + devDependencies)
123→    public static List<Dependency> ParsePackageJson(string json)
124→    {
125→        JsonNode? root;
126→        try
127→        {
128→            root = JsonNode.Parse(json);
129→        }
130→        catch (JsonException ex)
131→        {
132→            throw new ManifestParseException($"Failed to parse package.json: {ex.Message}", ex);
133→        }
134→
135→        if (root is null)
136→            throw new ManifestParseException("package.json content is null");
137→
138→        var deps = new List<Dependency>();
139→
140→        // Extract from "dependencies" and "devDependencies" sections
141→        ExtractDepsFromSection(root["dependencies"], deps);
142→        ExtractDepsFromSection(root["devDependencies"], deps);
143→
144→        return deps;
145→    }
146→
147→    private static void ExtractDepsFromSection(JsonNode? section, List<Dependency> deps)
148→    {
149→        if (section is not JsonObject obj) return;
150→        foreach (var kvp in obj)
151→        {
152→            var version = kvp.Value?.GetValue<string>() ?? "*";
153→            deps.Add(new Dependency(kvp.Key, version));
154→        }
155→    }
156→
157→    // Parse a requirements.txt string and extract all dependencies
158→    // Format: package_name[==|>=|~=|!=|<=|<|>]version  or just package_name
159→    public static List<Dependency> ParseRequirementsTxt(string content)
160→    {
161→        var deps = new List<Dependency>();
162→        // Regex to match: package_name followed by optional version specifier
163→        var pattern = new Regex(@"^\s*([a-zA-Z0-9_][a-zA-Z0-9._-]*)\s*((?:==|>=|<=|~=|!=|<|>).+)?\s*$");
164→
165→        foreach (var rawLine in content.Split('\n'))
166→        {
167→            var line = rawLine.Trim();
168→            // Skip empty lines and comments
169→            if (string.IsNullOrWhiteSpace(line) || line.StartsWith('#'))
170→                continue;
171→
172→            var match = pattern.Match(line);
173→            if (match.Success)
174→            {
175→                var name = match.Groups[1].Value;
176→                var version = match.Groups[2].Success ? match.Groups[2].Value : "*";
177→                deps.Add(new Dependency(name, version));
178→            }
179→        }
180→
181→        return deps;
182→    }
183→}
184→
185→// ── License Lookup ───────────────────────────────────────────────────────────
186→
187→// Orchestrates license lookups for a list of dependencies
188→public static class LicenseLookup
189→{
190→    // Look up licenses for all dependencies, returning a map of name -> license (or null)
191→    public static Dictionary<string, string?> LookupAll(
192→        List<Dependency> dependencies, ILicenseProvider provider)
193→    {
194→        var results = new Dictionary<string, string?>();
195→        foreach (var dep in dependencies)
196→        {
197→            results[dep.Name] = provider.GetLicense(dep.Name, dep.Version);
198→        }
199→        return results;
200→    }
201→}
202→
203→// ── Compliance Checker ───────────────────────────────────────────────────────
204→
205→// Checks dependencies against allow/deny license lists
206→public static class ComplianceChecker
207→{
208→    // Classify a single license against the config
209→    // Deny list takes precedence over allow list
210→    public static LicenseStatus ClassifyLicense(string? license, ComplianceConfig config)
211→    {
212→        if (license is null)
213→            return LicenseStatus.Unknown;
214→
215→        // Deny list takes precedence
216→        if (config.DeniedLicenses.Contains(license))
217→            return LicenseStatus.Denied;
218→
219→        if (config.AllowedLicenses.Contains(license))
220→            return LicenseStatus.Approved;
221→
222→        return LicenseStatus.Unknown;
223→    }
224→
225→    // Check all dependencies and return compliance results
226→    public static List<ComplianceResult> CheckAll(
227→        Dictionary<string, string?> licenseMap, ComplianceConfig config)
228→    {
229→        var results = new List<ComplianceResult>();
230→        foreach (var kvp in licenseMap)
231→        {
232→            var status = ClassifyLicense(kvp.Value, config);
233→            // We don't have version info in the license map, so use empty string
234→            results.Add(new ComplianceResult(kvp.Key, "", kvp.Value, status));
235→        }
236→        return results;
237→    }
238→}
239→
240→// ── Report Generator ─────────────────────────────────────────────────────────
241→
242→// Generates compliance reports in various formats (JSON, text)
243→public static class ReportGenerator
244→{
245→    // Generate a structured report from compliance results
246→    public static ComplianceReport Generate(List<ComplianceResult> results)
247→    {
248→        var entries = results
249→            .Select(r => new ReportEntry(r.DependencyName, r.Version, r.License, r.Status.ToString()))
250→            .ToList();
251→
252→        int approved = results.Count(r => r.Status == LicenseStatus.Approved);
253→        int denied = results.Count(r => r.Status == LicenseStatus.Denied);
254→        int unknown = results.Count(r => r.Status == LicenseStatus.Unknown);
255→        bool pass = denied == 0;
256→
257→        return new ComplianceReport(
258→            entries,
259→            new ReportSummary(results.Count, approved, denied, unknown, pass));
260→    }
261→
262→    // Serialize report to indented JSON
263→    public static string ToJson(ComplianceReport report)
264→    {
265→        var options = new JsonSerializerOptions
266→        {
267→            WriteIndented = true,
268→            PropertyNamingPolicy = JsonNamingPolicy.CamelCase
269→        };
270→        return JsonSerializer.Serialize(report, options);
271→    }
272→
273→    // Render report as a human-readable text table
274→    public static string ToText(ComplianceReport report)
275→    {
276→        var sb = new StringBuilder();
277→        sb.AppendLine("╔══════════════════════════════════════════════════════════════════╗");
278→        sb.AppendLine("║              Dependency License Compliance Report               ║");
279→        sb.AppendLine("╚══════════════════════════════════════════════════════════════════╝");
280→        sb.AppendLine();
281→
282→        // Table header
283→        sb.AppendLine($"{"Dependency",-30} {"Version",-15} {"License",-15} {"Status",-10}");
284→        sb.AppendLine(new string('-', 70));
285→
286→        // Table rows
287→        foreach (var entry in report.Entries)
288→        {
289→            var license = entry.License ?? "(unknown)";
290→            sb.AppendLine($"{entry.DependencyName,-30} {entry.Version,-15} {license,-15} {entry.Status,-10}");
291→        }
292→
293→        sb.AppendLine();
294→        sb.AppendLine($"Total: {report.Summary.Total}  |  " +
295→                       $"Approved: {report.Summary.Approved}  |  " +
296→                       $"Denied: {report.Summary.Denied}  |  " +
297→                       $"Unknown: {report.Summary.Unknown}");
298→        sb.AppendLine();
299→        sb.AppendLine(report.Summary.Pass ? "Result: PASS" : "Result: FAIL");
300→
301→        return sb.ToString();
302→    }
303→}
